#include 
using namespace std;

int main() {
    vector numbers = {10, 20, 30, 40, 50};

    // Remove the first occurrence of 30
    numbers.erase(numbers.begin() + 2); // Erases the element at index 2 (value 30)

    // Display the vector after erasing 30 using a normal for loop
    for (int i = 0; i < 4; i++) {  // After erasing, size becomes 4
        cout << numbers[i] << " ";
    }

    return 0;
}

